import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class NoConsecutiveBlankLinesRuleWithKDocTest {
    private val noConsecutiveBlankLinesRuleAssertThat = assertThatRule { NoConsecutiveBlankLinesRule() }

    @Test
    fun `double KDoc between declarations does NOT trigger needless blank line`() {
        val code = """
            class JsonReader {
                /**
                 * Foo
                 */
                /** Bar */
                var a = 0
            }
        """.trimIndent()
        noConsecutiveBlankLinesRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `double KDoc separated by a blank line DOES trigger needless blank line`() {
        val code = """
            class JsonReader {
                /**
                 * Foo
                 */

                /** Bar */
                var a = 0
            }
        """.trimIndent()
        noConsecutiveBlankLinesRuleAssertThat(code)
            .hasLintViolation(6, 1, "Needless blank line(s)")
    }
}
"}

